package main

import "fmt"

func main() {
	var qtdentrada int
	fmt.Scan(&qtdentrada)

	entrada := make([]string, qtdentrada)
	for i := range qtdentrada {
		fmt.Scan(&entrada[i])
	}
	var qtdconsulta int
	fmt.Scan(&qtdconsulta)

	consulta := make([]string, qtdconsulta)
	saida := make(map[string]int)
	for i := range qtdconsulta {
		fmt.Scan(&consulta[i])
	}

	for _, p := range entrada {
		if entrada[p] == consulta[p] {
			saida[p]++
		} else {
			saida[p] = 0
		}
	}

	for _, p := range entrada {
		fmt.Println(saida[p])
	}

}
